import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const m=JSON.parse('{"title":"第十五章 先赢眼前一剑","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第十五章-先赢眼前一剑.md","filePath":"永恒道途/正文/第一卷-山门有路/第十五章-先赢眼前一剑.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第十五章-先赢眼前一剑.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第十五章-先赢眼前一剑" tabindex="-1">第十五章 先赢眼前一剑 <a class="header-anchor" href="#第十五章-先赢眼前一剑" aria-label="Permalink to &quot;第十五章 先赢眼前一剑&quot;">​</a></h1><p>陈玄在药堂躺了七日。</p><p>前两日，他连坐起都要人扶。胸前钩伤重新缝合，断骨以木片固定，右臂经脉被血煞与强行凝剑伤了两次，稍一运气便像有砂砾在其中摩擦。</p><p>药堂医师给出的诊断很直接。</p><p>“一个月内不得动剑，三个月内不得再受重伤。否则下一次伤的不是经脉，是根基。”</p><p>陈玄没有讨价还价。</p><p>他比任何人都清楚暗伤的代价。炼气期看不出的细小裂痕，筑基时都可能变成拦住道途的墙。</p><p>七日里，刑律峰来问过三次话。</p><p>第一次问黑风涧伏杀经过，第二次核对石寨人数与地图，第三次则带来从红石谷查获的血魔宗物证。每一次询问的问题都有细微变化，若是临时编造的谎言，很容易前后矛盾。</p><p>陈玄没有隐瞒自己侦查与杀人的过程，只把掌天瓶从整条叙述里拿掉。</p><p>回脉草被解释为父亲札记中记载的配药法；七日破境则归因于生死耗空灵力、清除血煞后气脉贯通。两件事都不算寻常，却有迹可循，不至于指向一件能催熟灵药的至宝。</p><p>刑律长老最后问：“你在薛七储物袋里，只取了灵石，没有取血道功法？”</p><p>“弟子不修血道。来历不明的功法带回身上，未必是机缘。”</p><p>“那十余块灵石呢？”</p><p>“灵石没有功法禁制，也没有血气。弟子缺钱。”</p><p>长老看了他片刻，竟很轻地笑了一声。</p><p>“至少这句够实在。”</p><p>问话结束后，宗门奖赏很快下来。</p><p>外门贡献六十点，中品养脉丹一瓶，另有一次藏经阁二层的旁听资格。陆炳与郑衡的遗物已经送往家中，猎杀册上的其余身份牌也陆续找到对应弟子。</p><p>至于血魔宗据点，刑律峰当夜便拔掉了两处。红石谷却已人去楼空，只剩一座尚未完成的血阵。</p><p>那封写给“血魔子”的密信，被长老会列为机密。</p><p>第六日傍晚，任务殿为近期死在黑风山的弟子立了一块名碑。</p><p>碑上共有十二个名字。陆炳与郑衡排在最后，旁边刻着入宗年份与籍贯，没有写他们生前修为，也没有写谁在任务里立过多少功。</p><p>陈玄拄着木杖去看了一次。</p><p>陆家来了一个头发花白的妇人，抱着装有遗物的木匣，始终没有哭，只反复问执事，自己的儿子死前有没有受太多苦。郑衡的家人远在青云州南境，未能赶到，宗门便把他的储物袋与抚恤灵石封入信匣，由专人送回。</p><p>陈玄站在人群最后，没有上前告诉陆母，陆炳最后被獠熊拍中时叫得多惨。死者的真相应当被记住，却不是每一种痛苦都必须交给活着的人承受。</p><p>他只在众人散去后，把一束从药园带来的凝露草放在碑下。</p><p>凝露草不贵，连正式祭品都算不上。叶尖在暮色里结出十二滴清露，一滴对应一个名字。</p><p>韩执事不知何时站到身后：“宗门弟子每年都有人死。今日是他们，明日可能是你。”</p><p>“弟子知道。”</p><p>“怕吗？”</p><p>“怕。”陈玄看着碑上名字，“所以更要记清自己为什么出去，也要想好若回不来，留下些什么。”</p><p>韩执事沉默片刻：“你留下的猎杀册，至少让七个人有了死讯。对他们家里而言，这比一具找不到的尸体强。”</p><p>夕阳彻底落下后，陈玄才离开名碑。</p><p>从那日起，他不再把任务册只当作换贡献的凭证。每一次出门的路线、同伴和异常，他都会留下两份记录。一份带在身上，一份交给信得过的人。</p><p>谨慎不仅是替自己留退路。</p><p>有时，也是替没能回来的人留一句交代。</p><p>陈玄第一次知道，自己在石寨看见的名字，属于血魔宗少主。对方十八岁筑基，修炼《血煞魔功》，近两年一直在青云州边境活动。</p><p>薛七只是他手下一枚不起眼的棋子。</p><p>这个消息没有让陈玄热血沸腾，只让他更谨慎。</p><p>炼气六层与筑基之间隔着一个大境界。现在谈报仇或斩草除根，都只是把自己的命提前送到对方手里。</p><p>第八日，陈玄离开药堂。</p><p>韩执事在门外等他，递来一枚新的青木腰牌。正面是“青云外门”，背面刻着陈玄姓名，不再有药园试役或杂役字样。</p><p>“宗门查过你的任务履历。岁试前十六，黑风山立功，修为炼气六层。从今日起，转为正式外门弟子。”</p><p>陈玄接过腰牌：“药园的差事呢？”</p><p>“可停。”</p><p>“弟子想继续做。”</p><p>韩执事皱眉：“正式弟子每月有两块灵石与一瓶养气散，不必靠种药换口粮。”</p><p>“药园有灵田可练引水术，也能继续学辨灵药。弟子只减去晨间点卯，按贡献接圃。”</p><p>韩执事看了他一会儿：“随你。”</p><p>走到丁字九圃时，鲁老头正蹲在田边剪枯叶。</p><p>四个月前，陈玄救活的第一批凝露草已经长到齐膝高。最早恢复的那一株，叶心竟抽出一根细细花茎，顶端结着米粒大小的白色花苞。</p><p>“它真会开花。”陈玄道。</p><p>鲁老头没有回头：“老子说过的话还能有假？”</p><p>“这几日劳鲁叔照看。”</p><p>“药是药园的，不是替你照看。”老头剪下最后一片枯叶，才转身看他，“伤好多少？”</p><p>“能走，不能出剑。”</p><p>“活该。”</p><p>骂完，鲁老头从草棚取出一只陶罐。里面温着清淡药粥，米粒已经熬得软烂，浮着几片养脉叶。</p><p>陈玄在田埂边坐下，一口一口喝完。老头不问他杀了几个人，也不问血魔宗，只说哪片药圃生了虫、哪道沟渠被雨冲坏，仿佛他只是出门七日，又回来接着干活。</p><p>这种寻常让陈玄绷了许久的心慢慢落了地。</p><p>接下来的一个月，他没有碰剑。</p><p>白日照料药圃，夜里只做最缓的吐纳。右臂经脉每三日服一枚养脉丹，再以引水术牵引温水热敷。掌天瓶当月凝出的绿液，他只取一半催熟一株六年续脉藤，与宗门丹药交替使用；剩余一半仍封在瓶底。</p><p>第十日，胸前伤口结痂。</p><p>第二十日，断骨不再疼痛。</p><p>满一个月后，陈玄第一次重新握住青锋剑。</p><p>他没有尝试青元剑气，只在药田外空地做了一百次最基础的直刺。第一剑右臂仍有滞涩，第三十剑后逐渐舒展，到第一百剑，剑尖终于能稳稳停在同一点上。</p><p>鲁老头在旁边看完，只说：“还没废。”</p><p>陈玄笑了笑：“我也觉得。”</p><p>第二个月，宗门公布内门选拔名单。</p><p>外门岁试前百、修为炼气六层以上，或近两年有重大功绩者，皆可参加。三个月后开赛，前十获得内门资格，前三可入主殿接受各峰长老择徒。</p><p>陈玄凭岁试名次与黑风山功绩在列。</p><p>名单贴出的那日，围观弟子议论最多的不是叶承、秦岚等外门成名人物，而是“药园陈玄”四个字。</p><p>有人说他以炼气六层杀了炼气七层的血魔修士，实力深不可测；有人说那只是偷袭与运气，擂台上没有火场和毒粉，原形很快便会显露。</p><p>陈玄看过名单便离开，没有向任何人解释。</p><p>两种说法都有一部分是真的。</p><p>他能杀薛七，不代表正面强于薛七；他借了环境与准备，也不代表胜利只是运气。真正上台后，答案自然会出现。</p><p>王小虎也拿到参赛资格。</p><p>他如今炼气六层，修为比陈玄慢一层，基础剑法却练得极稳。两人在石桥对练时，王小虎第一次把陈玄逼到十招后才露出破绽。</p><p>第十一招，陈玄以剑背压住他的木剑。</p><p>王小虎喘着气坐在桥边：“小时候我爹总说你聪明，我还不服。现在看，不服也得服。”</p><p>“你第七招若不急着抢攻，输的是我。”</p><p>“少安慰我。”</p><p>“不是安慰。你的灵力比我纯，拖到三十招后，我未必占优。”</p><p>王小虎转头看他，忽然笑了：“那大比上真遇见，谁也别让。”</p><p>“好。”</p><p>第三个月末，陈玄将修为推进到炼气六层巅峰。</p><p>他没有冲关。</p><p>药堂医师说过三个月内不得再受重伤，而突破本身也是经脉承受的一次冲击。离大比还有一个月，强行提前几日没有意义。</p><p>最后一个月，他把掌天瓶新凝的整滴绿液用在一株聚气花上。药龄从四年增至十四年，没有夸张到数百年，也没有引来不可承受的药力。陈玄以三次药浴分开吸收，配合每日周天，把丹田气旋一点点填满。</p><p>选拔前第七日，瓶颈自然出现裂隙。</p><p>陈玄仍等了两日。</p><p>等右臂经脉完全没有滞涩，等四属灵气每一股都处在同样充盈的状态，他才在第五日夜里闭关。</p><p>没有狂暴吸纳，也没有灵药堆叠。</p><p>木水先入，金火后归。四属灵气沿着他用了两年多的次序运转四十九周天，丹田气旋在最后一周天向外扩开。</p><p>炼气七层。</p><p>突破后的第一件事不是试剑，而是继续调息到天明。直到境界不再浮动，陈玄才拔出青锋剑，在院中斩出一道青元剑气。</p><p>剑气离锋六尺，在石壁前自行散去。</p><p>比炼气六层时远了一倍，却还远远谈不上纵横数丈。</p><p>陈玄对这个结果很满意。</p><p>距离不是越远越好。六尺之内能保持锋芒不散，已经足够改变一场近身胜负。</p><p>大比前夜，王胖子提着食盒来到小院。</p><p>食盒里有两荤一素，还有一壶青云城米酒。他把菜摆好，又从储物袋里掏出三张护身符、两瓶回灵散和一张密密麻麻的参赛者名单。</p><p>“叶承，炼气九层，火系枪修；秦岚，炼气九层，丹峰秦家旁支，擅水火双术；赵无锋，炼气九层，枪快；韩牧，炼气八层后期，土墙难啃。”</p><p>王胖子边念边敲名单：“我能买到的消息都在这。至于钱，等你进前十再算。”</p><p>“若进不了？”</p><p>“那就把你每月的药材价再压半成。”</p><p>“想得美。”</p><p>王胖子嘿嘿一笑，给两人各倒半碗酒：“盘口里你进前十是一赔四，进前三一赔十二。我这次没多押，只押了十块灵石进前十。”</p><p>“上次你也说没多押。”</p><p>“上次我穷。现在家底厚了，十块当然不多。”</p><p>陈玄没有劝他收手，只把名单从头看了一遍。纸上记录的招式与修为可以参考，却不能当作真正的对手。人会藏招，也会在擂台上改变。</p><p>夜深后，王胖子离开。</p><p>陈玄没有去练剑台。他把青锋剑擦净，把符箓与丹药按使用顺序放入储物袋，随后将掌天瓶藏进最内层暗袋。</p><p>瓶底还有先前留下的半滴绿液。</p><p>它不能在擂台上使用，也不会替他挡下任何一剑。</p><p>明日真正能带上场的，只有炼气七层的修为、青元剑诀、两年多积下的判断，以及每一次从错误里留下来的经验。</p><p>窗外传来三声钟鸣。</p><p>陈玄熄灭灯火，闭目休息。</p><p>这一夜，他没有想苏婉是否会来看，也没有想自己会不会一战成名。</p><p>他只把王胖子名单上的第一个名字在心里过了一遍，然后让呼吸一点点归于平静。</p><p>明日上台，先赢眼前一剑。</p><p>（第十五章完）</p>',123)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
